code.glsl:
uniform float uDecay;
uniform float uMix;
uniform float uTime;
out vec4 fragColor;
void main() {
    vec2 uv = vUV.st;
    vec4 current = texture(sTD2DInputs[0], uv);
    vec4 feedback = texture(sTD2DInputs[1], uv);
    vec4 color = mix(feedback * uDecay, current, uMix);
    fragColor = TDOutputSwizzle(color);
}
